import{_ as r,Z as e,P as s,g as n,k as l,m as a}from"./chunks/framework.Dp5g00Bf.js";const m=JSON.parse('{"title":"office365的安装与激活","description":"","frontmatter":{},"headers":[],"relativePath":"views/2-软件📲/办公软件操作/office365的安装与激活/index.md","filePath":"views/2-软件📲/办公软件操作/office365的安装与激活/index.md","lastUpdated":1778336291000}'),d={name:"views/2-软件📲/办公软件操作/office365的安装与激活/index.md"};function h(c,t,g,p,f,u){const o=e("NolebaseGitContributors"),i=e("NolebaseGitChangelog");return s(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778336291000"},[t[0]||(t[0]=l('<h1 id="office365的安装与激活" tabindex="-1">office365的安装与激活 <a class="header-anchor" href="#office365的安装与激活" aria-label="Permalink to &quot;office365的安装与激活&quot;">​</a></h1><p>要在 Windows、mac 上下载并实现 Office 365 的准永久激活且支持更新，目前技术圈最主流、安全且开源的方法是使用 <strong>Microsoft Activation Scripts (MAS)</strong> 。</p><p>这种方法的核心原理是利用微软官方的 <strong>KMS（Key Management Service）</strong> 激活机制。虽然 Office 365 理论上是订阅制，但通过 MAS 可以将其转换为批量授权版本并自动续期，从而达到“永久激活”的效果。</p><hr><h2 id="第一步-下载并安装-office" tabindex="-1">第一步：下载并安装 Office <a class="header-anchor" href="#第一步-下载并安装-office" aria-label="Permalink to &quot;第一步：下载并安装 Office&quot;">​</a></h2><p>在激活之前，你必须先安装官方原版的 Office。建议使用微软官方的部署工具，确保纯净无毒。</p><ol><li><strong>推荐工具：<a href="https://otp.landian.vip/zh-cn/" target="_blank" rel="noreferrer">Office Tool Plus</a></strong> （开源、强大、无广告）。</li><li><strong>安装步骤：</strong><ul><li>下载并运行 Office Tool Plus。</li><li>在“部署”栏目中，产品选择 <strong>“Microsoft 365 应用程序”</strong> （或者 Office LTSC 2024 专业增强版，如果追求极度稳定）。</li><li>通道选择 <strong>“当前通道”</strong> （Current Channel）以获取最新更新。</li><li>点击“开始部署”，等待下载安装完成。</li></ul></li></ol><hr><h2 id="第二步-使用-mas-脚本激活" tabindex="-1">第二步：使用 MAS 脚本激活 <a class="header-anchor" href="#第二步-使用-mas-脚本激活" aria-label="Permalink to &quot;第二步：使用 MAS 脚本激活&quot;">​</a></h2><p>这是目前全球最推荐的激活方式，代码在 GitHub 开源，透明安全。</p><h3 id="_1-快捷操作-推荐" tabindex="-1">1. 快捷操作（推荐） <a class="header-anchor" href="#_1-快捷操作-推荐" aria-label="Permalink to &quot;1. 快捷操作（推荐）&quot;">​</a></h3><p>如果你能正常连接网络，可以直接通过 PowerShell 运行命令：</p><ol><li><p>在任务栏搜索框输入 <code>PowerShell</code>，右键点击 <strong>“以管理员身份运行”</strong> 。</p></li><li><p>输入以下命令并回车： <strong>PowerShell</strong></p><div class="language-PowerShell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">PowerShell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get.activated.win </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>稍等片刻，会弹出一个蓝底白字的交互菜单。</p></li></ol><h3 id="_2-选择激活选项" tabindex="-1">2. 选择激活选项 <a class="header-anchor" href="#_2-选择激活选项" aria-label="Permalink to &quot;2. 选择激活选项&quot;">​</a></h3><p>在菜单中你会看到几个数字选项：</p><ul><li><strong>按数字 [2] 选择 &quot;Ohook&quot;：</strong> * 这是目前激活 Office 365 的 <strong>神级方案</strong> 。 <ul><li><strong>优点：</strong> 它是永久性的（不再是 180 天循环），支持 Office 365 的所有特性（包括自动更新、登录账号、云端功能等），且不需要在后台运行任何破解软件。</li></ul></li><li><strong>或者按数字 [3] 选择 &quot;KMS38&quot;：</strong> * 这种方法会将有效期延长至 2038 年，同样非常稳定。</li></ul><h3 id="_3-等待成功" tabindex="-1">3. 等待成功 <a class="header-anchor" href="#_3-等待成功" aria-label="Permalink to &quot;3. 等待成功&quot;">​</a></h3><p>脚本会自动运行，当看到 <strong>&quot;Successfully Activated&quot;</strong> 的字样时，关闭窗口即可。</p><hr><h2 id="核心优势总结" tabindex="-1">核心优势总结 <a class="header-anchor" href="#核心优势总结" aria-label="Permalink to &quot;核心优势总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>特性</strong></th><th><strong>MAS (Ohook 模式)</strong></th><th><strong>传统激活补丁 (KMS)</strong></th></tr></thead><tbody><tr><td><strong>时效性</strong></td><td><strong>永久激活</strong></td><td>180 天需后台自动续期</td></tr><tr><td><strong>安全性</strong></td><td>开源脚本，无病毒隐患</td><td>容易被报毒，甚至携带后门</td></tr><tr><td><strong>更新支持</strong></td><td><strong>支持官方在线更新</strong></td><td>偶尔更新后失效</td></tr><tr><td><strong>账号登录</strong></td><td>支持登录个人微软账号</td><td>部分补丁登录后会报错</td></tr></tbody></table><hr><h2 id="⚠️-重要提醒" tabindex="-1">⚠️ 重要提醒 <a class="header-anchor" href="#⚠️-重要提醒" aria-label="Permalink to &quot;⚠️ 重要提醒&quot;">​</a></h2><ul><li><strong>卸载旧版：</strong> 在安装新 Office 之前，请务必先卸载电脑上自带的、或者之前安装失败的旧版本，防止激活冲突。</li><li><strong>关于“白嫖”：</strong> 虽然技术上可以实现，但如果你是企业用户或预算充足，建议支持正版订阅，可以获得 1TB 的 OneDrive 空间。</li><li><strong>杀毒软件：</strong> 运行脚本时，Windows Defender 可能会有提示，这是正常的误报，建议操作前临时关闭实时防护。</li></ul>',24)),a(o),a(i)])}const k=r(d,[["render",h]]);export{m as __pageData,k as default};
